import sql from "@/app/api/utils/sql";
import { getActor, requireAuthActor } from "@/app/api/utils/authz";

import { decryptFromString } from "../../../utils/encryption.js";
import { extractSpecsWithClaude } from "../../../utils/claude.js";
import { extractSpecsWithLlamaParse } from "../../../utils/llamaparse.js";
import { calculateFileHash } from "../../../utils/duplicate-detection.js";

function safeTrim(v) {
  return typeof v === "string" ? v.trim() : "";
}

function safeInt(v, fallback) {
  const n = Number.parseInt(String(v), 10);
  return Number.isFinite(n) ? n : fallback;
}

function normalizeId(id) {
  const n = safeInt(id, null);
  return n === null ? null : n;
}

function isUuid(value) {
  const v = safeTrim(value);
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(
    v,
  );
}

async function loadPresalesCopilotSettings(orgId) {
  const rows = await sql(
    `
    SELECT
      enabled,
      models,
      pdf_extraction_method,
      llamaparse_api_key,
      llamaparse_endpoint,
      llamaparse_mode
    FROM public.presales_copilot_settings
    WHERE org_id = $1::uuid
    LIMIT 1
    `,
    [orgId],
  );

  return rows?.[0] || null;
}

async function loadUserLlmConfig({ actor, orgId }) {
  const userId = actor?.userId ? String(actor.userId) : "";
  if (!userId) return null;

  let rows = [];
  rows = await sql(
    `SELECT settings FROM public.user_app_settings WHERE user_id = $1 AND org_id = $2::uuid LIMIT 1`,
    [userId, orgId],
  );

  if (!rows?.length) {
    rows = await sql(
      `SELECT settings FROM public.user_app_settings WHERE user_id = $1 AND org_id IS NULL LIMIT 1`,
      [userId],
    );
  }

  const settings = rows?.[0]?.settings || null;
  const llmConfig = settings?.llmConfig || null;
  if (!llmConfig || typeof llmConfig !== "object") return null;

  const { decryptIfNeeded } = await import("@/app/api/utils/crypto");
  const apiKeyRaw =
    typeof llmConfig.apiKey === "string" ? llmConfig.apiKey : "";
  const apiKey = apiKeyRaw ? await decryptIfNeeded(apiKeyRaw) : "";

  return { ...llmConfig, apiKey };
}

function normalizeJson(value, fallback) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function pickExtractionMethod(incoming, settingsRow) {
  const requested = safeTrim(incoming);
  if (requested === "llamaparse" || requested === "claude") return requested;

  const fallback = safeTrim(settingsRow?.pdf_extraction_method);
  if (fallback === "llamaparse" || fallback === "claude") return fallback;

  return "claude";
}

function buildStructuredLlmConfig({ userLlmConfig, modelsRow, purposeKey }) {
  const models = normalizeJson(modelsRow, {});
  const purpose =
    models?.[purposeKey] && typeof models[purposeKey] === "object"
      ? models[purposeKey]
      : {};

  const provider =
    safeTrim(purpose.provider) || safeTrim(userLlmConfig?.provider) || "openai";
  const model =
    safeTrim(purpose.model) || safeTrim(userLlmConfig?.model) || "gpt-4o";

  const temperature =
    typeof purpose.temperature === "number"
      ? purpose.temperature
      : typeof userLlmConfig?.temperature === "number"
        ? userLlmConfig.temperature
        : 0.2;

  const maxTokens =
    typeof purpose.max_tokens === "number"
      ? purpose.max_tokens
      : typeof userLlmConfig?.maxTokens === "number"
        ? userLlmConfig.maxTokens
        : 4096;

  const apiEndpoint =
    safeTrim(purpose.apiEndpoint) || safeTrim(userLlmConfig?.apiEndpoint);

  return {
    provider,
    model,
    temperature,
    maxTokens,
    topP: 1,
    frequencyPenalty: 0,
    presencePenalty: 0,
    apiEndpoint,
    apiKey: safeTrim(userLlmConfig?.apiKey),
    fallbackChain: Array.isArray(userLlmConfig?.fallbackChain)
      ? userLlmConfig.fallbackChain
      : [],
  };
}

function performMergeAnalysis(existingSpecs, newSpecs) {
  const result = {
    newFields: [],
    conflicts: [],
    enhancements: [],
  };

  function traverse(existingObj, newObj, path = []) {
    if (!newObj || typeof newObj !== "object") return;

    for (const [key, newValue] of Object.entries(newObj)) {
      const currentPath = [...path, key];
      const pathString = currentPath.join(".");

      if (
        !existingObj ||
        typeof existingObj !== "object" ||
        !(key in existingObj)
      ) {
        result.newFields.push({ path: pathString, value: newValue });
        continue;
      }

      const existingValue = existingObj[key];

      const bothObjects =
        existingValue &&
        typeof existingValue === "object" &&
        newValue &&
        typeof newValue === "object" &&
        !Array.isArray(existingValue) &&
        !Array.isArray(newValue);

      if (bothObjects) {
        traverse(existingValue, newValue, currentPath);
        continue;
      }

      const bothArrays =
        Array.isArray(existingValue) && Array.isArray(newValue);
      if (bothArrays) {
        const additions = newValue.filter((v) => !existingValue.includes(v));
        if (additions.length > 0) {
          const merged = [...new Set([...existingValue, ...newValue])];
          result.enhancements.push({
            path: pathString,
            existing: existingValue,
            additions,
            merged,
          });
        }
        continue;
      }

      if (JSON.stringify(existingValue) !== JSON.stringify(newValue)) {
        result.conflicts.push({
          path: pathString,
          existingValue,
          newValue,
        });
      }
    }
  }

  traverse(existingSpecs, newSpecs);
  return result;
}

export async function POST(request, { params }) {
  try {
    const actor = await getActor(request);
    const authRes = requireAuthActor(actor);
    if (authRes) return authRes;

    if (!actor?.isPlatformAdmin) {
      return Response.json({ error: "Forbidden" }, { status: 403 });
    }

    const productId = normalizeId(params?.id);
    if (!productId) {
      return Response.json({ error: "Invalid product id" }, { status: 400 });
    }

    const body = await request.json().catch(() => null);

    const orgId = safeTrim(body?.orgId);
    const fileUrl = safeTrim(body?.fileUrl);
    const extractionMethod = safeTrim(body?.extractionMethod);

    if (!orgId || !fileUrl) {
      return Response.json(
        { error: "Missing orgId or fileUrl" },
        { status: 400 },
      );
    }

    if (!isUuid(orgId)) {
      return Response.json({ error: "orgId must be a UUID" }, { status: 400 });
    }

    const productRows = await sql(
      `SELECT * FROM public.presales_copilot_products WHERE id = $1 LIMIT 1`,
      [productId],
    );

    if (!productRows?.length) {
      return Response.json({ error: "Product not found" }, { status: 404 });
    }

    const product = productRows[0];
    if (String(product.org_id) !== String(orgId)) {
      return Response.json(
        { error: "Product orgId mismatch" },
        { status: 400 },
      );
    }

    const settingsRow = await loadPresalesCopilotSettings(orgId);
    if (!settingsRow || !settingsRow.enabled) {
      return Response.json(
        { error: "Presales Copilot not enabled for this org" },
        { status: 403 },
      );
    }

    const chosenMethod = pickExtractionMethod(extractionMethod, settingsRow);

    // hash the remote file (best-effort)
    const resp = await fetch(fileUrl);
    const mimeType =
      safeTrim(resp.headers.get("content-type")) || "application/pdf";
    const ab = resp.ok ? await resp.arrayBuffer() : null;
    const fileHash = ab ? await calculateFileHash(ab) : "";

    // load user llm config
    const userLlmConfig = await loadUserLlmConfig({ actor, orgId });
    if (!userLlmConfig?.apiKey) {
      return Response.json(
        {
          error: "llm_not_configured",
          message:
            "LLM API key not configured. Go to Settings → LLM and add an API key, then retry.",
        },
        { status: 400 },
      );
    }

    const structuredLlmConfig = buildStructuredLlmConfig({
      userLlmConfig,
      modelsRow: settingsRow.models,
      purposeKey: "document_extractor",
    });

    let extractedData = null;

    if (chosenMethod === "llamaparse") {
      const llamaparseApiKeyEncrypted = safeTrim(
        settingsRow.llamaparse_api_key,
      );
      const llamaparseApiKey = llamaparseApiKeyEncrypted
        ? await decryptFromString(llamaparseApiKeyEncrypted)
        : "";

      if (!llamaparseApiKey) {
        return Response.json(
          {
            error: "llamaparse_not_configured",
            message:
              "LlamaParse API key not configured. Go to Settings → Presales Copilot and add the LlamaParse key.",
          },
          { status: 400 },
        );
      }

      const llamaparseConfig = {
        tier: "agentic",
        version: "latest",
        pollIntervalMs: 5000,
        maxPollAttempts: 24,
      };

      const res = await extractSpecsWithLlamaParse({
        pdfUrl: fileUrl,
        fileName: "spec.pdf",
        mimeType,
        llamaparseApiKey,
        llamaparseConfig,
        llmConfig: structuredLlmConfig,
      });

      extractedData = res.extracted;
    } else {
      if (
        String(structuredLlmConfig.provider || "").toLowerCase() !== "anthropic"
      ) {
        return Response.json(
          {
            error: "invalid_extraction_provider",
            message:
              "Claude-native PDF extraction requires provider=anthropic. Update Presales Copilot → Document Extractor provider, or switch to LlamaParse extraction.",
          },
          { status: 400 },
        );
      }

      const extractionConfig =
        normalizeJson(settingsRow.models, {})?.document_extractor || {};
      extractedData = await extractSpecsWithClaude(
        fileUrl,
        extractionConfig,
        structuredLlmConfig.apiKey,
      );
    }

    const existingSpecs =
      product?.specs_json && typeof product.specs_json === "object"
        ? product.specs_json
        : {};

    const mergeResult = performMergeAnalysis(
      existingSpecs,
      extractedData?.specs || {},
    );

    return Response.json(
      {
        ok: true,
        orgId,
        productId,
        fileUrl,
        fileHash,
        extractedData,
        mergeResult,
      },
      { headers: { "Cache-Control": "no-store" } },
    );
  } catch (error) {
    console.error(
      "POST /api/presales-copilot/products/[id]/enrich error:",
      error,
    );
    return Response.json(
      { error: error?.message || "Enrichment failed" },
      { status: 500 },
    );
  }
}

